import{_ as r,o as t,c as o,a2 as d}from"./chunks/framework.C90q7Ucc.js";const b=JSON.parse('{"title":"命令体系","description":"","frontmatter":{},"headers":[],"relativePath":"product/commands.md","filePath":"product/commands.md","lastUpdated":1781278400000}'),c={name:"product/commands.md"};function a(s,e,i,n,h,m){return t(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="命令体系" tabindex="-1">命令体系 <a class="header-anchor" href="#命令体系" aria-label="Permalink to &quot;命令体系&quot;">​</a></h1><p>IM 命令从用户视角分为五组。命令入口是 <a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/dispatch.ts" target="_blank" rel="noreferrer">src/bridge/command/dispatch.ts</a>，具体处理按工作流拆在 <a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/" target="_blank" rel="noreferrer">src/bridge/command/</a> 下；会话、绑定、线程接管和归档的业务规则归 <a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/session/" target="_blank" rel="noreferrer">src/bridge/session/</a> 所有，command 层主要负责 slash 解析、用户文案、卡片和 delivery。</p><table tabindex="0"><thead><tr><th>分组</th><th>典型命令</th><th>功能</th></tr></thead><tbody><tr><td>会话和线程</td><td><code>/t</code>、<code>/new</code>、<code>/clear</code>、<code>/t rename</code>、<code>/t unbind</code></td><td>接管、新建、云文档群聊模式、切换、归档、重命名、解绑会话</td></tr><tr><td>runtime 设置</td><td><code>/runtime</code>、<code>/provider</code>、<code>/model</code>、<code>/mode</code>、<code>/reasoning</code>、<code>/sandbox</code>、<code>/network</code>、<code>/cd</code></td><td>修改当前会话的运行参数</td></tr><tr><td>状态和诊断</td><td><code>/</code>、<code>/status</code>、<code>/check</code>、<code>/doctor</code>、<code>/his</code></td><td>查看状态、健康检查、历史和排障</td></tr><tr><td>终端和文件</td><td><code>/shell</code>、<code>/tmux-*</code>、<code>/pty-screen</code>、<code>/cat</code>、<code>/file</code></td><td>执行命令、观察终端、发送文件</td></tr><tr><td>自动化和管理</td><td><code>/auto</code>、<code>/auto-script</code>、<code>/require-at</code>、<code>/ui</code>、<code>/set</code>、<code>/hot-update</code></td><td>定时任务、通道策略、显示和全局设置</td></tr></tbody></table><p>从本机 <code>audit.jsonl</code> 的实际使用看，高频命令集中在 <code>/provider</code>、<code>/clear</code>、<code>/t</code>、<code>/mode</code>、<code>/tmux-screen</code>、<code>/new</code>、<code>/runtime</code>、<code>/pty-screen</code>、<code>/set</code> 和 <code>/hot-update</code>。这说明新用户文档应优先讲清楚“接管会话、清理/新建会话、切 provider、观察终端屏幕、调整配置”这些路径，再补完整命令索引。</p><h2 id="用户使用原则" tabindex="-1">用户使用原则 <a class="header-anchor" href="#用户使用原则" aria-label="Permalink to &quot;用户使用原则&quot;">​</a></h2><ul><li>直接发送普通文本：继续当前绑定会话。</li><li>发送 <code>//...</code>：把以 <code>/</code> 开头的内容作为模型 prompt，而不是 bridge 命令。</li><li>未绑定会话时，普通文本会进入临时草稿线程；正式接管用 <code>/t</code>。</li><li>修改当前会话参数优先用 <code>/runtime</code>、<code>/provider</code>、<code>/model</code>、<code>/cd</code> 等会话级命令。</li><li>修改全局默认值用 <code>/set</code>；卡片按 TOML section 写入 <code>~/.codelark/config.toml</code>。</li><li><code>/doctor</code> 可不带参数；也可使用 <code>/doctor bridge_id:d3c20e05 2026-06-04 17:48</code> 或 <code>/doctor d3c20e05 2026-06-04 17:48</code>，让当前会话读取结构化 JSONL <code>bridge.log</code> 时优先用目标 id 和时间点搜索，并优先检查 <code>level=ERROR/WARN</code>、<code>event</code>、<code>msg</code>、<code>chat</code>、<code>lane</code> 等字段。</li></ul><h2 id="设计模块" tabindex="-1">设计模块 <a class="header-anchor" href="#设计模块" aria-label="Permalink to &quot;设计模块&quot;">​</a></h2><table tabindex="0"><thead><tr><th>命令主题</th><th>模块</th></tr></thead><tbody><tr><td>帮助</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/help.ts" target="_blank" rel="noreferrer">src/bridge/command/help.ts</a></td></tr><tr><td>会话和线程</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/session/" target="_blank" rel="noreferrer">src/bridge/session/</a>；slash 聚合入口在 <a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/session-thread.ts" target="_blank" rel="noreferrer">src/bridge/command/session-thread.ts</a></td></tr><tr><td>runtime 设置</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/runtime-settings.ts" target="_blank" rel="noreferrer">src/bridge/command/runtime-settings.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/provider-settings.ts" target="_blank" rel="noreferrer">src/bridge/command/provider-settings.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/runtime-bootstrap.ts" target="_blank" rel="noreferrer">src/bridge/command/runtime-bootstrap.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/runtime-session.ts" target="_blank" rel="noreferrer">src/bridge/command/runtime-session.ts</a></td></tr><tr><td>全局设置</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/global-settings.ts" target="_blank" rel="noreferrer">src/bridge/command/global-settings.ts</a></td></tr><tr><td>状态</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/status.ts" target="_blank" rel="noreferrer">src/bridge/command/status.ts</a></td></tr><tr><td>诊断和历史</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/diagnostics.ts" target="_blank" rel="noreferrer">src/bridge/command/diagnostics.ts</a></td></tr><tr><td>控制和权限</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/control.ts" target="_blank" rel="noreferrer">src/bridge/command/control.ts</a></td></tr><tr><td>tmux</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/tmux.ts" target="_blank" rel="noreferrer">src/bridge/command/tmux.ts</a>、<a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/tmux-args.ts" target="_blank" rel="noreferrer">src/bridge/command/tmux-args.ts</a></td></tr><tr><td>pty 屏幕</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/pty.ts" target="_blank" rel="noreferrer">src/bridge/command/pty.ts</a></td></tr><tr><td>shell</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/shell.ts" target="_blank" rel="noreferrer">src/bridge/command/shell.ts</a></td></tr><tr><td>自动任务</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/auto.ts" target="_blank" rel="noreferrer">src/bridge/command/auto.ts</a></td></tr><tr><td>热更新</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/hot-update.ts" target="_blank" rel="noreferrer">src/bridge/command/hot-update.ts</a></td></tr><tr><td>展示格式</td><td><a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/presentation/" target="_blank" rel="noreferrer">src/bridge/command/presentation/</a></td></tr></tbody></table><h2 id="命令展示" tabindex="-1">命令展示 <a class="header-anchor" href="#命令展示" aria-label="Permalink to &quot;命令展示&quot;">​</a></h2><p>IM 内 <code>/h</code> 的文案由 <a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/command/help.ts" target="_blank" rel="noreferrer">src/bridge/command/help.ts</a> 生成。Web 工作台“命令说明”页面在 <a href="https://github.com/huiyeruzhou/codelark/blob/main/src/operator-ui/shell.ts" target="_blank" rel="noreferrer">src/operator-ui/shell.ts</a> 中渲染。新增命令时需要同步这两处用户入口。</p><p>模块边界：生产代码中只有 <code>bridge/host</code> 直接调用 <code>bridge/command</code>；通道、turn、runtime 等横向 owner 不直接 import command，command 也不反向 import <code>bridge/host/*</code>。跨 turn 和 command 共用的 agent question 回调协议位于 <a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/callbacks/agent-question.ts" target="_blank" rel="noreferrer">src/bridge/callbacks/agent-question.ts</a>。命令需要的聊天绑定和 startup target 共享入口分别是 <a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/session/channel-router.ts" target="_blank" rel="noreferrer">src/bridge/session/channel-router.ts</a> 和 <a href="https://github.com/huiyeruzhou/codelark/blob/main/src/bridge/startup-notice-target.ts" target="_blank" rel="noreferrer">src/bridge/startup-notice-target.ts</a>。</p>',11)])])}const u=r(c,[["render",a]]);export{b as __pageData,u as default};
